    10	    public static func download(modelSize: String, onProgress: ((Double) -> Void)? = nil) throws {
    11	        let modelFileName = "ggml-\(modelSize).bin"
    12	        let modelsDir = Config.configDir.appendingPathComponent("models")
    13	        let destPath = modelsDir.appendingPathComponent(modelFileName)
