    23	        guard let url = URL(string: urlString) else {
    24	            throw ModelDownloadError.downloadFailed
    25	        }
    26	
    27	        print("Downloading \(modelSize) model from \(urlString)...")
    28	
    29	        let downloader = ModelDownloader()
    30	        downloader.onProgress = onProgress
    31	        downloader.destPath = destPath
    32	
    33	        let semaphore = DispatchSemaphore(value: 0)
    34	        var downloadError: Error?
    35	
    36	        downloader.completion = { error in
    37	            downloadError = error
