    83	    public static func isValidGGMLFile(at url: URL) -> Bool {
    84	        guard let handle = try? FileHandle(forReadingFrom: url) else { return false }
    85	        defer { handle.closeFile() }
    86	        guard let magic = try? handle.read(upToCount: 4), magic.count == 4 else { return false }
    87	        // GGML magic: 0x67676d6c ("ggml"), GGJT magic: 0x67676a74 ("ggjt"), GGUF magic: 0x46554747 ("GGUF")
    88	        let magicU32 = magic.withUnsafeBytes { $0.load(as: UInt32.self) }
    89	        let knownMagics: Set<UInt32> = [0x67676d6c, 0x67676a74, 0x46554747]
    90	        return knownMagics.contains(magicU32)
    91	    }
